+		json.NewEncoder(w).Encode(TokenResponse{})
+	}))
+	defer server.Close()
+
+	oldURL := ClaudeTokenURL
+	ClaudeTokenURL = server.URL
+	defer func() { ClaudeTokenURL = oldURL }()
